/**
 * NURBS Control Point Data - Species-specific NURBS handle data
 *
 * Ported from the original Infinigen .npy files at:
 *   infinigen/assets/objects/creatures/parts/nurbs_data/
 *
 * Each entry contains the decomposed NURBS handles for a species:
 *   - skeleton: The spine centerline (9 points × 3 xyz)
 *   - profiles: Cross-section offsets from skeleton (9 × 8 or 9 × 12 × 3)
 *   - rads: Mean radii at each cross-section
 *   - proportions: Relative lengths between skeleton segments
 *
 * The data was decomposed using factorize_nurbs_handles() which:
 *   1. Computes the skeleton as the mean of each cross-section
 *   2. Rotates profiles to face the x-axis (removing skeleton curvature)
 *   3. Normalizes profiles by their mean radius
 *
 * This allows species-specific body shapes while still supporting
 * parametric variation via the decomposed parameters.
 */

// ── Type Definitions ──────────────────────────────────────────────────

/**
 * Decomposed NURBS handle data for a single species body part.
 *
 * The skeleton defines the spine centerline, and profiles define
 * cross-section shapes relative to the local frame at each skeleton point.
 */
export interface NURBSSpeciesData {
  /** "body" or "head" */
  partType: 'body' | 'head';
  /** Species category + name, e.g. "feline_cheetah" */
  subType: string;
  /** Array shape [u, v, 3] of the original handles */
  shape: [number, number, 3];
  /** Spine centerline: 9 points × [x, y, z] */
  skeleton: number[][];
  /** Parameter values along skeleton [0..1] */
  ts: number[];
  /** Cross-section offsets from skeleton in local frame (x=forward, y=lateral, z=vertical) */
  profiles: number[][][];
  /** Normalized profiles (divided by mean radius) */
  profilesNorm: number[][][];
  /** Mean radius at each cross-section */
  rads: number[];
  /** Total spine length */
  totalLength: number;
  /** Relative segment lengths between skeleton points */
  proportions: number[];
  /** Spine direction angles in degrees (x-z plane) */
  thetasDeg: number[];
  /** Vertical offset ratios for each skeleton segment */
  skeletonYoffs: number[];
  /** Maximum lateral extent across all cross-sections */
  maxWidth: number;
  /** Maximum vertical extent across all cross-sections */
  maxHeight: number;
}

/**
 * Map from species key (e.g. "body_feline_cheetah") to decomposed NURBS data.
 *
 * Key format: {part}_{category}_{species}, where:
 *   part = "body" | "head"
 *   category = "feline" | "herbivore" | "bird" | "fish" | "insect" | "carnivore"
 *   species = specific animal name
 */
export type NURBSControlPointDataset = Map<string, NURBSSpeciesData>;

// ── Species Data ─────────────────────────────────────────────────────

/**
 * Pre-loaded NURBS control point data for all species.
 *
 * Usage:
 * ```ts
 * import { CONTROL_POINT_DATA, getSpeciesData } from './nurbsControlPointData';
 *
 * // Get cheetah body data
 * const cheetahBody = getSpeciesData('body', 'feline_cheetah');
 *
 * // Check if data exists for a species
 * if (cheetahBody) {
 *   console.log('Cheetah body length:', cheetahBody.totalLength);
 * }
 * ```
 */
