// ── Lookup Helpers ───────────────────────────────────────────────────

/**
 * Look up species data by part type and species name.
 *
 * @param partType - "body" or "head"
 * @param speciesName - Species key like "feline_cheetah", "herbivore_cow", etc.
 * @returns The species data, or undefined if not found
 */
export function getSpeciesData(
  partType: 'body' | 'head',
  speciesName: string,
): NURBSSpeciesData | undefined {
  return CONTROL_POINT_DATA.get(`${partType}_${speciesName}`);
}

/**
 * Get all species names for a given part type.
 *
 * @param partType - "body" or "head"
 * @returns Array of species keys (e.g., ["feline_cheetah", "feline_housecat", ...])
 */
export function getSpeciesNames(partType: 'body' | 'head' = 'body'): string[] {
  const result: string[] = [];
  for (const [key, data] of CONTROL_POINT_DATA) {
    if (data.partType === partType) {
      result.push(data.subType);
    }
  }
  return result;
}

/**
 * Get all species data for a given creature category.
 *
 * @param category - Category like "feline", "herbivore", "bird", "fish", "insect"
 * @returns Map of species key to data
 */
export function getCategoryData(
  category: string,
): Map<string, NURBSSpeciesData> {
  const result = new Map<string, NURBSSpeciesData>();
  for (const [key, data] of CONTROL_POINT_DATA) {
    if (data.subType.startsWith(category)) {
      result.set(key, data);
    }
  }
  return result;
}

/**
 * Check if control point data exists for a given species.
 */
export function hasSpeciesData(
  partType: 'body' | 'head',
  speciesName: string,
): boolean {
  return CONTROL_POINT_DATA.has(`${partType}_${speciesName}`);
}

/**
 * Get body profile configuration defaults derived from species data.
 * Maps species NURBS data to BodyProfileConfig parameters.
 *
 * @param speciesName - Species key like "feline_cheetah"
 * @returns Partial BodyProfileConfig, or undefined if no data
 */
export function getSpeciesBodyProfileConfig(
  speciesName: string,
): import('./NURBSBodyProfile').BodyProfileConfig | undefined {
  const data = getSpeciesData('body', speciesName);
  if (!data) return undefined;

  return {
    bodyLength: data.totalLength,
    bodyWidth: data.maxWidth * 2,
    bodyHeight: data.maxHeight * 2,
    headSize: data.proportions[0] + data.proportions[1],
    tailLength: data.proportions.slice(-2).reduce((a, b) => a + b, 0),
    neckLength: data.proportions[1],
    spineCurvature: data.skeletonYoffs.reduce((a, b) => a + Math.abs(b), 0) * 0.1,
    bilateralSymmetry: true,
    uResolution: data.shape[0],
    vResolution: data.shape[1],
    degreeU: 3,
    degreeV: 3,
  };
}
